using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");
        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_Null_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooShort_Throws()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooLong_Throws()
    {
        _formatter.FormatPhoneNumber("12345678901");
    }

    // ── BuildGreeting ──────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_UsesDefaultTitle()
    {
        var result = _formatter.BuildGreeting("Smith");
        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");
        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Doe");
        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_AnyName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_AnyName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Montague", "Ms.");
        StringAssert.Contains(result, "Montague");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_NullName_Throws()
    {
        _formatter.BuildGreeting(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // ── GenerateSlug ───────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ReplacedWithDashes()
    {
        var result = _formatter.GenerateSlug("C# is great!!!");
        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_Trimmed()
    {
        var result = _formatter.GenerateSlug("  My Post  ");
        Assert.AreEqual("my-post", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("---leading dashes");
        Assert.IsFalse(result.StartsWith('-'));
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("trailing dashes---");
        Assert.IsFalse(result.EndsWith('-'));
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("Unit Testing 101!");
        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceTitle_Throws()
    {
        _formatter.GenerateSlug("   ");
    }

    // ── FormatCurrency ─────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollar()
    {
        var result = _formatter.FormatCurrency(19.99m);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(9.99m, "€");
        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(50m);
        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ExactFormat()
    {
        var result = _formatter.FormatCurrency(1234.56m);
        Assert.AreEqual("$1234.56", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.00m);
        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);
        Assert.AreEqual("$0.00", result);
    }
}

